// === Output layer: Linear(32, 1) ===
static const float W3[32] = {-0.11915176f, -0.04374711f, 0.15131718f, 0.10202046f, 0.09796528f, -0.13507180f, -0.11584416f, 0.04446051f, 0.00074514f, -0.00152115f, 0.00375608f, -0.07738209f, -0.00104327f, -0.11065917f, 0.04845160f, 0.16695173f, 0.10042389f, -0.00447423f, -0.09941283f, 0.14573303f, -0.00193450f, -0.00309112f, 0.00817205f, -0.09051963f, -0.07517017f, 0.01123670f, -0.05991425f, 0.00818674f, -0.00888990f, 0.14325990f, -0.00247269f, -0.06193204f};
static const float b3[1] = {-0.00101514f};

/**
 * Run RL policy inference.
 *
 * @param theta     Pendulum angle (rad)
 * @param alpha     Wheel angle (rad)
 * @param theta_dot Pendulum angular velocity (rad/s)
 * @param alpha_dot Wheel angular velocity (rad/s)
 * @return Residual voltage in [-RESIDUAL_SCALE, +RESIDUAL_SCALE]
 */
static inline float rl_inference(float theta, float alpha, float theta_dot, float alpha_dot) {
    float obs[RL_INPUT_DIM] = {theta, alpha, theta_dot, alpha_dot};
    float h1[RL_HIDDEN_DIM];
    float h2[RL_HIDDEN_DIM];

    // Normalize observations
    for (int i = 0; i < RL_INPUT_DIM; i++) {
        obs[i] = (obs[i] - obs_mean[i]) / obs_std[i];
        if (obs[i] > OBS_CLIP)  obs[i] = OBS_CLIP;
        if (obs[i] < -OBS_CLIP) obs[i] = -OBS_CLIP;
    }

    // Layer 1: h1 = tanh(W1 * obs + b1)
    for (int i = 0; i < RL_HIDDEN_DIM; i++) {
        float sum = b1[i];
        for (int j = 0; j < RL_INPUT_DIM; j++) {
            sum += W1[i][j] * obs[j];
        }
        h1[i] = tanhf(sum);
    }

    // Layer 2: h2 = tanh(W2 * h1 + b2)
    for (int i = 0; i < RL_HIDDEN_DIM; i++) {
        float sum = b2[i];
        for (int j = 0; j < RL_HIDDEN_DIM; j++) {
            sum += W2[i][j] * h1[j];
        }
        h2[i] = tanhf(sum);
    }

    // Output: action = W3 * h2 + b3
    float action = b3[0];
    for (int j = 0; j < RL_HIDDEN_DIM; j++) {
        action += W3[j] * h2[j];
    }

    // Clip to [-1, 1] then scale
    if (action > 1.0f)  action = 1.0f;
    if (action < -1.0f) action = -1.0f;

    return action * RL_RESIDUAL_SCALE;
}

